import React, { useState } from 'react';
import { Container, Row, Col, Card, Form, Button, Alert } from 'react-bootstrap';
import { loginAction } from '../services/AuthAPI';
import { useAuth } from '../contexts/AuthContext';
import { useNavigate } from 'react-router-dom';
import ModalConfirm from './ModalConfirm';

function LoginForm() {
    const [username, setUsername] = useState('');
    const [password, setPassword] = useState('');
    const [errors, setErrors] = useState({});
    const [showModal, setShowModal] = useState(false);

    const navigate = useNavigate();
    const { state, dispatch } = useAuth();

    const handleInputChange = (setter, field) => (e) => {
        setter(e.target.value);
        setErrors((prev) => ({ ...prev, [field]: '', message: '' }));
    };

    const validate = () => {
        const newErrors = {};

        if (!username) {
            newErrors.username = 'Username is required';
        } else if (username.includes('@')) {
            const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
            if (!emailRegex.test(username)) {
                newErrors.username = 'Invalid email format';
            }
        }

        if (!password) {
            newErrors.password = 'Password is required';
        } else if (password.length < 6) {
            newErrors.password = 'Password must be at least 6 characters';
        }

        return newErrors;
    };

    const handleLogin = async (e) => {
        e.preventDefault();

        // Validation cục bộ
        const newErrors = validate();
        if (Object.keys(newErrors).length > 0) {
            setErrors(newErrors);
            return;
        }

        // Gọi API
        const result = await loginAction(dispatch, { username, password });

        if (result.success) {
            // Kiểm tra role admin
            if (result.user.role !== 'admin') {
                setErrors({ message: 'Access denied. Admins only.' });
                return;
            }

            // Kiểm tra trạng thái tài khoản
            if (result.user.status === 'locked') {
                setErrors({ message: 'Access is denied. Your account is locked.' });
                return;
            }

            // Hiển thị modal xác nhận
            setShowModal(true);
            setTimeout(() => {
                setShowModal(false);
                navigate('/');
            }, 3000);
        }
    };

    const handleCancel = () => {
        setUsername('');
        setPassword('');
        setErrors({});
    };

    return (
        <Container className="mt-5">
            <Row className="justify-content-md-center">
                <Col xs={12} md={6}>
                    <Card className="shadow-sm">
                        <Card.Header className="bg-white py-3">
                            <h3 className="text-center mb-0">Login</h3>
                        </Card.Header>
                        <Card.Body className="p-4">
                            {/* Hiển thị lỗi global */}
                            {(state.error || errors.message) && (
                                <Alert variant="danger">{state.error || errors.message}</Alert>
                            )}

                            <Form onSubmit={handleLogin} noValidate>
                                <Form.Group controlId="username" className="mb-3">
                                    <Form.Label>Username or email</Form.Label>
                                    <Form.Control
                                        type="text"
                                        placeholder="Enter username or email"
                                        value={username}
                                        onChange={handleInputChange(setUsername, 'username')}
                                        disabled={state.loading}
                                        isInvalid={!!errors.username}
                                    />
                                    <Form.Control.Feedback type="invalid">
                                        {errors.username}
                                    </Form.Control.Feedback>
                                </Form.Group>

                                <Form.Group controlId="password" className="mb-3">
                                    <Form.Label>Password</Form.Label>
                                    <Form.Control
                                        type="password"
                                        value={password}
                                        onChange={handleInputChange(setPassword, 'password')}
                                        placeholder="Enter password"
                                        disabled={state.loading}
                                        isInvalid={!!errors.password}
                                    />
                                    <Form.Control.Feedback type="invalid">
                                        {errors.password}
                                    </Form.Control.Feedback>
                                </Form.Group>

                                <div className="d-flex gap-2 mt-4">
                                    <Button
                                        variant="primary"
                                        type="submit"
                                        className="flex-fill"
                                        disabled={state.loading}
                                    >
                                        {state.loading ? 'Logging in...' : 'Login'}
                                    </Button>
                                    <Button
                                        variant="secondary"
                                        type="button"
                                        className="flex-fill"
                                        onClick={handleCancel}
                                        disabled={state.loading}
                                    >
                                        Cancel
                                    </Button>
                                </div>
                            </Form>
                        </Card.Body>
                    </Card>
                </Col>
            </Row>

            {/* Modal xác nhận đăng nhập thành công */}
            <ModalConfirm
                show={showModal}
                title="Login Successful"
                message="You have successfully logged in. Redirecting to dashboard..."
                onConfirm={() => setShowModal(false)}
                onCancel={() => setShowModal(false)}
            />
        </Container>
    );
}

export default LoginForm;
